import React, { useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  BarChart3, GitMerge, Search, Network, Droplet, 
  Cpu, Layers, AlignLeft, Repeat, Calculator, Crosshair, FlaskConical,
  Box, Terminal
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, SORTING_TEMPLATE, 
  CONNECTIVITY_TEMPLATE, PERCOLATION_TEMPLATE, REACTION_TEMPLATE, 
  SEARCH_TEMPLATE, MEMORY_TEMPLATE, STACK_TEMPLATE, 
  QUEUE_TEMPLATE, ITERATOR_TEMPLATE, TWOSTACK_TEMPLATE, 
  MERGE_TEMPLATE, CONVEX_TEMPLATE 
} from './templates';

type TabName = 'Write' | 'Insert' | 'Math/Sci' | 'Algorithms' | 'Data Structs';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');

  if (readOnly) return null;

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
    <button 
      onClick={action} 
      className="btn-icon" 
      title={title} 
      style={{ color: color, padding: '0.4rem', margin: '0 1px', borderRadius: '4px' }}
    >
      <Icon size={16} />
    </button>
  );

  const Group = ({ children, label }: { children: React.ReactNode, label?: string }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2px', padding: '0 6px', borderRight: '1px solid var(--border-color)', position: 'relative' }}>
      {children}
      {label && <span style={{ position: 'absolute', bottom: '-2px', left: 0, right: 0, textAlign: 'center', fontSize: '7px', color: 'var(--text-muted)', textTransform: 'uppercase', pointerEvents: 'none', opacity: 0.5 }}>{label}</span>}
    </div>
  );

  // Filtered tabs to only show the requested ones
  const visibleTabs: TabName[] = ['Write', 'Insert', 'Math/Sci'];

  return (
    <div className="editor-toolbar" style={{ borderBottom: '1px solid var(--border-color)' }}>
       {/* New Pill-style Tabs */}
       <div className="flex px-4 py-2 gap-2 bg-[var(--bg-toolbar)] overflow-x-auto no-scrollbar">
          {visibleTabs.map(tab => (
             <button
               key={tab}
               onClick={() => setActiveTab(tab)}
               style={{
                 padding: '0.25rem 0.75rem',
                 fontSize: '0.75rem',
                 fontWeight: 500,
                 borderRadius: '4px',
                 border: '1px solid var(--border-color)',
                 transition: 'all 0.2s',
                 backgroundColor: activeTab === tab ? 'var(--text-main)' : 'var(--bg-main)',
                 color: activeTab === tab ? 'var(--bg-main)' : 'var(--text-main)',
                 cursor: 'pointer'
               }}
             >
               {tab}
             </button>
          ))}
       </div>

       {/* Tools Area */}
       <div className="px-2 pb-2 flex items-center overflow-x-auto bg-[var(--bg-toolbar)] h-10 no-scrollbar">
          {activeTab === 'Write' && (
            <>
              <Group>
                <ToolbarButton icon={Bold} title="Bold" action={() => insertFormat('**', '**')} />
                <ToolbarButton icon={Italic} title="Italic" action={() => insertFormat('*', '*')} />
                <ToolbarButton icon={Strikethrough} title="Strikethrough" action={() => insertFormat('~~', '~~')} />
              </Group>
              <Group>
                <ToolbarButton icon={Heading1} title="Heading 1" action={() => insertFormat('# ', '', true)} />
                <ToolbarButton icon={Heading2} title="Heading 2" action={() => insertFormat('## ', '', true)} />
                <ToolbarButton icon={Heading3} title="Heading 3" action={() => insertFormat('### ', '', true)} />
              </Group>
              <Group>
                <ToolbarButton icon={List} title="Bullet List" action={() => insertFormat('- ', '', true)} />
                <ToolbarButton icon={ListOrdered} title="Numbered List" action={() => insertFormat('1. ', '', true)} />
                <ToolbarButton icon={CheckSquare} title="Check List" action={() => insertFormat('- [ ] ', '', true)} />
              </Group>
              <Group>
                <ToolbarButton icon={Quote} title="Quote" action={() => insertFormat('> ', '', true)} />
              </Group>
            </>
          )}

          {activeTab === 'Insert' && (
            <>
              <Group>
                <ToolbarButton icon={Link} title="Link" action={() => insertFormat('[', '](url)')} />
                <ToolbarButton icon={Image} title="Image" action={() => insertFormat('![alt text](', ')')} />
                <ToolbarButton icon={Table} title="Table" action={() => insertFormat('| Header 1 | Header 2 |\n| -------- | -------- |\n| Cell 1   | Cell 2   |', '', true)} />
              </Group>
              <Group>
                <ToolbarButton icon={Code} title="Inline Code" action={() => insertFormat('`', '`')} />
                <ToolbarButton icon={Terminal} title="Code Block" action={() => insertFormat('```\n', '\n```', true)} />
              </Group>
              <Group>
                <ToolbarButton icon={Minus} title="Horizontal Rule" action={() => insertFormat('---\n', '', true)} />
              </Group>
              <Group>
                <ToolbarButton icon={Workflow} title="Mermaid Diagram" action={() => insertFormat('```mermaid\n', '\n```', true)} color="#c084fc" />
                <ToolbarButton icon={Activity} title="Interactive Plot" action={() => insertFormat(PLOT_TEMPLATE, '', true)} color="#c084fc" />
                <ToolbarButton icon={Box} title="3D Model" action={() => insertFormat('<model-viewer src="url" auto-rotate camera-controls></model-viewer>', '', true)} color="#c084fc" />
              </Group>
            </>
          )}

          {activeTab === 'Math/Sci' && (
            <>
              <Group label="Mathematics">
                <ToolbarButton icon={Sigma} title="LaTeX Math" action={() => insertFormat('$$\n', '\n$$', true)} color="#60a5fa" />
              </Group>
              <Group label="Chemistry">
                <ToolbarButton icon={Hexagon} title="Organic Molecule (SMILES)" action={() => insertFormat('```smiles\n', '\n```', true)} color="#60a5fa" />
                <ToolbarButton icon={FlaskConical} title="Chemical Reaction Balancer" action={() => insertFormat(REACTION_TEMPLATE, '', true)} color="#60a5fa" />
              </Group>
              <Group label="Physics">
                <ToolbarButton icon={Atom} title="Physics Engine" action={() => insertFormat(PHYSICS_TEMPLATE, '', true)} color="#f87171" />
              </Group>
            </>
          )}
       </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, 
  Upload, 
  FileJson, 
  Settings, 
  X,
  Palette,
  PanelLeft,
  FileText,
  ExternalLink
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, ImportData, AppTheme } from './types';
import { initialNodes } from './initialData';

declare global {
  interface Window {
    html2pdf: any;
  }
}

const themes: Record<string, AppTheme> = {
  dark: {
    name: 'Dark',
    bgMain: '#030712', 
    bgSidebar: '#111827',
    textMain: '#f3f4f6', 
    textMuted: '#9ca3af', 
    border: '#1f2937', 
    accent: '#3b82f6', 
    hover: 'rgba(255, 255, 255, 0.05)'
  },
  light: {
    name: 'Light',
    bgMain: '#ffffff',
    bgSidebar: '#f3f4f6',
    textMain: '#111827',
    textMuted: '#6b7280',
    border: '#e5e7eb',
    accent: '#2563eb',
    hover: 'rgba(0, 0, 0, 0.05)'
  },
  navy: {
    name: 'Navy',
    bgMain: '#0f172a',
    bgSidebar: '#1e293b',
    textMain: '#f1f5f9',
    textMuted: '#94a3b8',
    border: '#334155',
    accent: '#38bdf8',
    hover: 'rgba(255, 255, 255, 0.1)'
  },
  dracula: {
    name: 'Dracula',
    bgMain: '#282a36',
    bgSidebar: '#21222c',
    textMain: '#f8f8f2',
    textMuted: '#bd93f9',
    border: '#44475a',
    accent: '#ff79c6',
    hover: 'rgba(255, 255, 255, 0.1)'
  }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(initialNodes);
  const [activeFileId, setActiveFileId] = useState<string | null>('algo-01-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs', 'folder-algo', 'folder-algo-pt1']));
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [currentTheme, setCurrentTheme] = useState<AppTheme>(themes.dark);
  const [customThemeMode, setCustomThemeMode] = useState(false);

  useEffect(() => {
    const savedFs = localStorage.getItem('markgenius-fs');
    if (savedFs) {
      try {
        setNodes(JSON.parse(savedFs));
      } catch (e) {
        console.error("Failed to load filesystem", e);
      }
    }
    const savedTheme = localStorage.getItem('markgenius-theme');
    if (savedTheme) {
        try { setCurrentTheme(JSON.parse(savedTheme)); } catch(e) {}
    }
  }, []);

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('markgenius-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('markgenius-fs', JSON.stringify(nodes));
  }, [nodes]);

  const activeNode = nodes.find(n => n.id === activeFileId);

  const handleAddFile = (parentId: string | null) => {
    const newNode: FileNode = {
      id: uuidv4(),
      parentId,
      name: 'Untitled',
      type: NodeType.FILE,
      content: '',
      createdAt: Date.now()
    };
    setNodes(prev => [...prev, newNode]);
    setActiveFileId(newNode.id);
    if (parentId) {
      setExpandedFolders(prev => new Set(prev).add(parentId));
    }
  };

  const handleAddFolder = (parentId: string | null) => {
    const newNode: FileNode = {
      id: uuidv4(),
      parentId,
      name: 'New Folder',
      type: NodeType.FOLDER,
      content: '',
      createdAt: Date.now()
    };
    setNodes(prev => [...prev, newNode]);
    if (parentId) {
      setExpandedFolders(prev => new Set(prev).add(parentId));
    }
  };

  const handleDeleteNode = (id: string) => {
    const getDescendants = (nodeId: string): string[] => {
      const children = nodes.filter(n => n.parentId === nodeId);
      let ids = children.map(c => c.id);
      children.forEach(c => {
        if (c.type === NodeType.FOLDER) {
          ids = [...ids, ...getDescendants(c.id)];
        }
      });
      return ids;
    };

    const idsToDelete = new Set([id, ...getDescendants(id)]);
    setNodes(prev => prev.filter(n => !idsToDelete.has(n.id)));
    if (activeFileId && idsToDelete.has(activeFileId)) setActiveFileId(null);
  };

  const handleRenameNode = (id: string, newName: string) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, name: newName } : n));
  };

  const handleToggleFolder = (id: string) => {
    setExpandedFolders(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleMoveNode = (nodeId: string, newParentId: string | null) => {
      if (nodeId === newParentId) return;
      if (newParentId) {
          const nodeToMove = nodes.find(n => n.id === nodeId);
          if (nodeToMove && nodeToMove.type === NodeType.FOLDER) {
               const getAllDescendants = (pId: string): string[] => {
                    const children = nodes.filter(n => n.parentId === pId);
                    let descendants = children.map(c => c.id);
                    children.forEach(c => {
                        if (c.type === NodeType.FOLDER) {
                            descendants = [...descendants, ...getAllDescendants(c.id)];
                        }
                    });
                    return descendants;
               };
               const descendants = getAllDescendants(nodeId);
               if (descendants.includes(newParentId)) {
                   alert("Cannot move a folder into its own child.");
                   return;
               }
          }
      }
      setNodes(prev => prev.map(n => n.id === nodeId ? { ...n, parentId: newParentId } : n));
  };

  const handleContentChange = (content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  };

  const exportToJson = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `backup-${new Date().toISOString().slice(0, 10)}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importFromJson = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes) {
          setNodes(data.nodes);
          setActiveFileId(null);
        }
      } catch (err) {
        alert("Invalid JSON file");
      }
    };
    reader.readAsText(file);
  };

  const exportToPdf = () => {
    if (!activeNode) return;
    const element = document.getElementById('markdown-preview');
    if (!element) {
        alert("Please open the preview mode or split view to export PDF.");
        return;
    }
    const opt = {
      margin: 10,
      filename: `${activeNode.name}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };
    if (window.html2pdf) {
        window.html2pdf().set(opt).from(element).save();
    } else {
        alert("PDF library not loaded.");
    }
  };

  const handleThemePresetChange = (presetKey: string) => {
      setCustomThemeMode(false);
      setCurrentTheme(themes[presetKey]);
  };

  const handleCustomColorChange = (key: keyof AppTheme, value: string) => {
      setCustomThemeMode(true);
      setCurrentTheme(prev => ({
          ...prev,
          name: 'Custom',
          [key]: value
      }));
  };

  return (
    <div className="app-container">


      {/* Sidebar */}
      <div 
        className="sidebar-wrapper"
        style={{ 
            width: isSidebarOpen ? '280px' : '0', 
            position: window.innerWidth < 768 ? 'fixed' : 'relative',
            height: '100%',
            zIndex: 40,
            transform: (window.innerWidth < 768 && !mobileMenuOpen) ? 'translateX(-100%)' : 'translateX(0)',
            transition: 'transform 0.3s ease, width 0.3s ease'
        }} 
      >
         <div style={{ width: '280px', height: '100%', display: 'flex', flexDirection: 'column' }}>
             <Sidebar 
                nodes={nodes}
                activeFileId={activeFileId}
                expandedFolders={expandedFolders}
                onFileSelect={(id) => { setActiveFileId(id); setMobileMenuOpen(true); }}
                onToggleFolder={handleToggleFolder}
                onAddFile={handleAddFile}
                onAddFolder={handleAddFolder}
                onDeleteNode={handleDeleteNode}
                onRenameNode={handleRenameNode}
                onMoveNode={handleMoveNode}
             />
             <button 
                onClick={() => setMobileMenuOpen(true)} 
                className="btn-icon md:hidden"
                style={{ position: 'absolute', top: '0.5rem', right: '0.5rem' }}
             >
             </button>
         </div>
      </div>

      {/* Main Content */}
      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                <button 
                  onClick={() => setIsSidebarOpen(!isSidebarOpen)}
                  className="btn-icon"
                  style={{ display: window.innerWidth < 768 ? 'none' : 'flex' }}
                  title={isSidebarOpen ? "Close Explorer" : "Open Explorer"}
                >
                  <PanelLeft size={20} />
                </button>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                  <h1 className="app-title">MathSci</h1>
                  <a 
                    href="https://orcid.org" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="btn"
                    style={{ 
                      padding: '0.2rem 0.5rem', 
                      fontSize: '0.65rem', 
                      color: '#a6ce39', 
                      borderColor: 'rgba(166, 206, 57, 0.3)',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '0.25rem'
                    }}
                  >
                    ORCID <ExternalLink size={10} />
                  </a>
                </div>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button 
                    onClick={() => setShowSettings(true)}
                    className="btn"
                    title="Settings"
                >
                    <Settings size={14} style={{ color: 'var(--text-muted)' }}/>
                    <span style={{ display: window.innerWidth < 640 ? 'none' : 'inline' }}>Settings</span>
                </button>

                <div className="divider" style={{ height: '1.5rem', background: 'var(--border-color)', width: '1px', margin: '0 0.5rem' }}></div>

                <button onClick={exportToPdf} className="btn">
                    <Download size={14} style={{ color: '#f87171' }}/>
                    <span style={{ display: window.innerWidth < 640 ? 'none' : 'inline' }}>PDF</span>
                </button>

                <label className="btn" style={{ cursor: 'pointer' }}>
                    <Upload size={14} style={{ color: '#4ade80' }}/>
                    <span style={{ display: window.innerWidth < 640 ? 'none' : 'inline' }}>Import</span>
                    <input type="file" accept=".json" style={{ display: 'none' }} onChange={importFromJson}/>
                </label>

                <button onClick={exportToJson} className="btn">
                    <FileJson size={14} style={{ color: '#facc15' }}/>
                    <span style={{ display: window.innerWidth < 640 ? 'none' : 'inline' }}>Backup</span>
                </button>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden', position: 'relative' }}>
            {activeNode && activeNode.type === NodeType.FILE ? (
                <Editor 
                    content={activeNode.content} 
                    fileName={activeNode.name}
                    onChange={handleContentChange} 
                />
            ) : (
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-muted)' }}>
                    <div style={{ width: '4rem', height: '4rem', borderRadius: '9999px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '1rem', backgroundColor: 'var(--bg-sidebar)' }}>
                        <FileText size={32} />
                    </div>
                    <p>Select a file to start editing</p>
                </div>
            )}
        </div>
      </div>

      {/* Settings Modal */}
      {showSettings && (
          <div className="modal-overlay">
              <div className="modal">
                  <div className="modal-header">
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                          <Palette size={18} style={{ color: 'var(--accent-color)' }} />
                          Theme Settings
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon">
                          <X size={20} />
                      </button>
                  </div>

                  <div className="modal-body">
                      <div style={{ marginBottom: '1.5rem' }}>
                          <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.75rem', color: 'var(--text-muted)' }}>Presets</label>
                          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                              {Object.entries(themes).map(([key, theme]) => (
                                  <button
                                    key={key}
                                    onClick={() => handleThemePresetChange(key)}
                                    style={{
                                        padding: '0.75rem', borderRadius: '0.25rem', border: `1px solid ${theme.border}`, textAlign: 'left', fontSize: '0.875rem', fontWeight: 500, display: 'flex', alignItems: 'center', gap: '0.5rem',
                                        backgroundColor: theme.bgMain, color: theme.textMain,
                                        outline: (!customThemeMode && currentTheme.name === theme.name) ? '2px solid var(--accent-color)' : 'none',
                                        cursor: 'pointer'
                                    }}
                                  >
                                      <div style={{ width: '1rem', height: '1rem', borderRadius: '50%', backgroundColor: theme.accent, border: '1px solid #888' }}></div>
                                      {theme.name}
                                  </button>
                              ))}
                          </div>
                      </div>

                      <div>
                           <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.75rem', color: 'var(--text-muted)' }}>Custom Colors</label>
                           <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                               {[
                                 { k: 'bgMain', l: 'Main Background' },
                                 { k: 'bgSidebar', l: 'Sidebar Background' },
                                 { k: 'textMain', l: 'Text Color' },
                                 { k: 'accent', l: 'Accent Color' }
                               ].map(({k, l}) => (
                                   <div key={k} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                       <span style={{ fontSize: '0.875rem' }}>{l}</span>
                                       <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                           <span style={{ fontSize: '0.75rem', fontFamily: 'monospace', opacity: 0.5 }}>{(currentTheme as any)[k]}</span>
                                           <input 
                                              type="color" 
                                              value={(currentTheme as any)[k]}
                                              onChange={(e) => handleCustomColorChange(k as keyof AppTheme, e.target.value)}
                                              style={{ width: '2rem', height: '2rem', border: 'none', borderRadius: '0.25rem', padding: 0, cursor: 'pointer' }}
                                           />
                                       </div>
                                   </div>
                               ))}
                           </div>
                      </div>
                  </div>

                  <div className="modal-footer">
                      <button 
                        onClick={() => setShowSettings(false)}
                        className="btn btn-primary"
                      >
                          Done
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  BarChart3, GitMerge, Search, Network, Droplet, 
  Cpu, Layers, AlignLeft, Repeat, Calculator, Crosshair, FlaskConical,
  Box, Terminal
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, SORTING_TEMPLATE, 
  CONNECTIVITY_TEMPLATE, PERCOLATION_TEMPLATE, REACTION_TEMPLATE, 
  SEARCH_TEMPLATE, MEMORY_TEMPLATE, STACK_TEMPLATE, 
  QUEUE_TEMPLATE, ITERATOR_TEMPLATE, TWOSTACK_TEMPLATE, 
  MERGE_TEMPLATE, CONVEX_TEMPLATE 
} from './templates';

type TabName = 'Write' | 'Insert' | 'Math/Sci' | 'Algorithms' | 'Data Structs';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');

  if (readOnly) return null;

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
