import React, { useState, useEffect, useRef } from 'react';
import { balanceEquation } from '../../utils/chemUtils';
import { ArrowRight, FlaskConical, RefreshCw } from 'lucide-react';

// Sub-component for rendering a molecule card
const MolCard = ({ 
    formula, 
    count, 
    side, 
    index, 
    onDragStart 
}: { 
    formula: string, 
    count: number, 
    side: 'reactants' | 'products', 
    index: number,
    onDragStart: (e: React.DragEvent, side: string, index: number) => void
}) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        if (!window.SmilesDrawer || !canvasRef.current) return;
        const style = getComputedStyle(document.body);
        const textColor = style.getPropertyValue('--text-main').trim();
        const options = { width: 100, height: 80, padding: 5, bondThickness: 1.0, color: textColor };

        // Simple mapping from formula to SMILES for demo purposes
        const smilesMap: Record<string, string> = {
            "CH4": "C",
            "O2": "O=O",
            "CO2": "O=C=O",
            "H2O": "O",
            "H2": "[H][H]",
            "N2": "N#N",
            "NH3": "N"
        };

        const smiles = smilesMap[formula] || "";

        if(smiles) {
            const drawer = new window.SmilesDrawer.Drawer(options);
            window.SmilesDrawer.parse(smiles, (tree: any) => {
                drawer.draw(tree, canvasRef.current, 'dark', false);
            });
        }
    }, [formula]);

    return (
        <div 
            draggable 
            onDragStart={(e) => onDragStart(e, side, index)}
            style={{ 
                padding: '0.5rem', 
                border: '1px solid var(--border-color)', 
                borderRadius: '0.5rem', 
                background: 'var(--bg-main)',
                display: 'flex', 
                flexDirection: 'column', 
                alignItems: 'center',
                cursor: 'grab',
                minWidth: '120px'
            }}
        >
            <div style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '0.25rem' }}>
                <span style={{ color: 'var(--accent-color)' }}>{count}</span> {formula}
            </div>
            <canvas ref={canvasRef} />
        </div>
    );
};

export const ChemicalBalancer = ({ configStr }: { configStr: string }) => {
    const [state, setState] = useState<{reactants: string[], products: string[]}>({ reactants: [], products: [] });
    const [coeffs, setCoeffs] = useState<number[]>([]);
    const [title, setTitle] = useState("Chemical Reaction");

    useEffect(() => {
        try {
            const parsed = JSON.parse(configStr);
            setState({ 
                reactants: parsed.reactants || [], 
                products: parsed.products || [] 
            });
            if(parsed.title) setTitle(parsed.title);
        } catch(e) {}
    }, [configStr]);

    useEffect(() => {
        const calculated = balanceEquation(state.reactants, state.products);
        if (calculated) setCoeffs(calculated);
        else setCoeffs(new Array(state.reactants.length + state.products.length).fill(1));
    }, [state]);

    const handleDragStart = (e: React.DragEvent, side: string, index: number) => {
        e.dataTransfer.setData('molecule', JSON.stringify({ side, index }));
    };

    const handleDrop = (e: React.DragEvent, targetSide: 'reactants' | 'products') => {
        e.preventDefault();
        const data = e.dataTransfer.getData('molecule');
        if (!data) return;
        const { side: sourceSide, index } = JSON.parse(data);

        if (sourceSide === targetSide) return;

        setState(prev => {
            const sourceList = [...(prev as any)[sourceSide]];
            const targetList = [...(prev as any)[targetSide]];
            const [moved] = sourceList.splice(index, 1);
            targetList.push(moved);
            return {
                ...prev,
                [sourceSide]: sourceList,
                [targetSide]: targetList
            };
        });
    };

    return (
        <div className="viz-container">
            <h3 style={{ margin: '0 0 1rem 0', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <FlaskConical size={18} color="var(--accent-color)" />
                {title}
            </h3>

            <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)', marginBottom: '1rem' }}>
                Drag molecules to see the equation balance: 
                <strong style={{ color: 'var(--text-main)', marginLeft: '0.5rem' }}>
                    {state.reactants.map((r, i) => `${coeffs[i] || '?'} ${r}`).join(' + ')} 
                    {' -> '}
                    {state.products.map((p, i) => `${coeffs[state.reactants.length + i] || '?'} ${p}`).join(' + ')}
                </strong>
            </p>

            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', overflowX: 'auto', paddingBottom: '1rem' }}>
                {/* Reactants Drop Zone */}
                <div 
                    onDragOver={(e) => e.preventDefault()}
                    onDrop={(e) => handleDrop(e, 'reactants')}
                    style={{ 
                        flex: 1, 
                        minHeight: '150px', 
                        border: '2px dashed var(--border-color)', 
                        borderRadius: '0.5rem',
                        padding: '1rem',
                        display: 'flex',
                        gap: '0.5rem',
                        flexWrap: 'wrap',
                        background: 'rgba(0,0,0,0.1)'
                    }}
                >
                    {state.reactants.map((r, i) => (
                        <MolCard 
                            key={`${r}-${i}-r`} 
                            formula={String(r)} 
                            count={Number(coeffs[i] || 1)} 
                            side="reactants" 
                            index={i} 
                            onDragStart={handleDragStart} 
                        />
                    ))}
                    {state.reactants.length === 0 && <span style={{ margin: 'auto', color: 'var(--text-muted)' }}>Drop Reactants Here</span>}
                </div>

                <ArrowRight size={24} style={{ color: 'var(--text-muted)' }} />

                {/* Products Drop Zone */}
                <div 
                    onDragOver={(e) => e.preventDefault()}
                    onDrop={(e) => handleDrop(e, 'products')}
                    style={{ 
                        flex: 1, 
                        minHeight: '150px', 
                        border: '2px dashed var(--border-color)', 
                        borderRadius: '0.5rem',
                        padding: '1rem',
                        display: 'flex',
                        gap: '0.5rem',
                        flexWrap: 'wrap',
                        background: 'rgba(0,0,0,0.1)'
                    }}
                >
                    {state.products.map((p, i) => (
                        <MolCard 
                            key={`${p}-${i}-p`} 
                            formula={String(p)} 
                            count={Number(coeffs[state.reactants.length + i] || 1)} 
                            side="products" 
                            index={i} 
                            onDragStart={handleDragStart} 
                        />
                    ))}
                    {state.products.length === 0 && <span style={{ margin: 'auto', color: 'var(--text-muted)' }}>Drop Products Here</span>}
                </div>
            </div>

            <button onClick={() => setState({ reactants: ["CH4", "O2"], products: ["CO2", "H2O"] })} className="btn" style={{ marginTop: '0.5rem' }}>
                <RefreshCw size={14} /> Reset to Methane Combustion
            </button>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, 
  Upload, 
  FileJson, 
  Settings, 
  X,
  Palette,
  PanelLeft,
  FileText,
  ExternalLink
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, ImportData, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: {
    name: 'Dark',
    bgMain: '#030712', 
    bgSidebar: '#111827',
    textMain: '#f3f4f6', 
    textMuted: '#9ca3af', 
    border: '#1f2937', 
    accent: '#3b82f6', 
    hover: 'rgba(255, 255, 255, 0.05)'
  },
  light: {
    name: 'Light',
    bgMain: '#ffffff',
    bgSidebar: '#f3f4f6',
    textMain: '#111827',
    textMuted: '#6b7280',
    border: '#e5e7eb',
    accent: '#2563eb',
    hover: 'rgba(0, 0, 0, 0.05)'
  }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const activeNode = nodes.find(n => n.id === activeFileId);

  const handleAddFile = (parentId: string | null) => {
    const newNode: FileNode = {
      id: uuidv4(),
      parentId,
      name: 'Untitled.md',
      type: NodeType.FILE,
      content: '',
      createdAt: Date.now()
    };
    setNodes(prev => [...prev, newNode]);
    setActiveFileId(newNode.id);
  };

  const handleAddFolder = (parentId: string | null) => {
    const newNode: FileNode = {
      id: uuidv4(),
      parentId,
      name: 'New Folder',
      type: NodeType.FOLDER,
      content: '',
      createdAt: Date.now()
    };
    setNodes(prev => [...prev, newNode]);
  };

  const handleDeleteNode = (id: string) => {
    setNodes(prev => prev.filter(n => n.id !== id));
    if (activeFileId === id) setActiveFileId(null);
  };

  const handleRenameNode = (id: string, newName: string) => {
    setNodes(prev => prev.map(n => n.id === id ? { ...n, name: newName } : n));
  };

  const handleToggleFolder = (id: string) => {
    setExpandedFolders(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleMoveNode = (nodeId: string, newParentId: string | null) => {
    setNodes(prev => prev.map(n => n.id === nodeId ? { ...n, parentId: newParentId } : n));
  };

  const handleContentChange = (content: string) => {
    if (!activeFileId) return;
    setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n));
  };

  const exportToJson = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mathsci-backup.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importFromJson = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes) {
          setNodes(data.nodes);
          setActiveFileId(data.nodes.find(n => n.type === NodeType.FILE)?.id || null);
        }
      } catch (err) {
        alert("Invalid workspace file.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  return (
    <div className="app-container">
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={handleToggleFolder}
            onAddFile={handleAddFile}
            onAddFolder={handleAddFolder}
            onDeleteNode={handleDeleteNode}
            onRenameNode={handleRenameNode}
            onMoveNode={handleMoveNode}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon">
                  <PanelLeft size={18} />
                </button>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <h1 className="app-title">MathSci</h1>
                    <a href="https://orcid.org" target="_blank" rel="noopener noreferrer" className="btn" style={{ padding: '0.1rem 0.4rem', borderColor: '#a6ce39', color: '#a6ce39', fontSize: '10px' }}>
                        ORCID <ExternalLink size={10} style={{ marginLeft: '2px' }} />
                    </a>
                </div>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => setShowSettings(true)} className="btn">
                    <Settings size={14} /> Theme
                </button>
                <div className="divider"></div>
                <button onClick={exportToJson} className="btn"><FileJson size={14} style={{ color: '#facc15' }}/> Backup</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                    <Upload size={14} style={{ color: '#4ade80' }}/> Import
                    <input type="file" accept=".json" style={{ display: 'none' }} onChange={importFromJson}/>
                </label>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeNode ? (
                <Editor 
                    content={activeNode.content} 
                    fileName={activeNode.name}
                    onChange={handleContentChange} 
                />
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-muted)' }}>
                    <p>Select a file from the explorer</p>
                </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay">
              <div className="modal">
                  <div className="modal-header">
                      <span>UI Preferences</span>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div className="modal-body" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                    {Object.entries(themes).map(([k, t]) => (
                        <button key={k} onClick={() => setCurrentTheme(t)} className="btn" style={{ height: '80px', background: t.bgMain, color: t.textMain }}>
                            {t.name}
                        </button>
                    ))}
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

