import React, { useState, useEffect, useRef } from 'react';
import { balanceEquation } from '../../utils/chemUtils';
import { ArrowRight, FlaskConical, RefreshCw } from 'lucide-react';

// Sub-component for rendering a molecule card
const MolCard = ({ 
    formula, 
    count, 
    side, 
    index, 
    onDragStart 
}: { 
    formula: string, 
    count: number, 
    side: 'reactants' | 'products', 
    index: number,
    onDragStart: (e: React.DragEvent, side: string, index: number) => void
}) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        if (!window.SmilesDrawer || !canvasRef.current) return;
        const style = getComputedStyle(document.body);
        const textColor = style.getPropertyValue('--text-main').trim();
        const options = { width: 100, height: 80, padding: 5, bondThickness: 1.0, color: textColor };

        // Simple mapping from formula to SMILES for demo purposes
        const smilesMap: Record<string, string> = {
            "CH4": "C",
            "O2": "O=O",
            "CO2": "O=C=O",
            "H2O": "O",
            "H2": "[H][H]",
            "N2": "N#N",
            "NH3": "N"
        };

        const smiles = smilesMap[formula] || "";

        if(smiles) {
            const drawer = new window.SmilesDrawer.Drawer(options);
            window.SmilesDrawer.parse(smiles, (tree: any) => {
                drawer.draw(tree, canvasRef.current, 'dark', false);
            });
        }
    }, [formula]);

    return (
        <div 
            draggable 
            onDragStart={(e) => onDragStart(e, side, index)}
            style={{ 
                padding: '0.5rem', 
                border: '1px solid var(--border-color)', 
                borderRadius: '0.5rem', 
                background: 'var(--bg-main)',
                display: 'flex', 
                flexDirection: 'column', 
                alignItems: 'center',
                cursor: 'grab',
                minWidth: '120px'
            }}
        >
            <div style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '0.25rem' }}>
                <span style={{ color: 'var(--accent-color)' }}>{count}</span> {formula}
            </div>
            <canvas ref={canvasRef} />
        </div>
    );
};

export const ChemicalBalancer = ({ configStr }: { configStr: string }) => {
    const [state, setState] = useState<{reactants: string[], products: string[]}>({ reactants: [], products: [] });
    const [coeffs, setCoeffs] = useState<number[]>([]);
    const [title, setTitle] = useState("Chemical Reaction");

    useEffect(() => {
        try {
            const parsed = JSON.parse(configStr);
            setState({ 
                reactants: parsed.reactants || [], 
                products: parsed.products || [] 
            });
            if(parsed.title) setTitle(parsed.title);
        } catch(e) {}
    }, [configStr]);

    useEffect(() => {
        const calculated = balanceEquation(state.reactants, state.products);
        if (calculated) setCoeffs(calculated);
        else setCoeffs(new Array(state.reactants.length + state.products.length).fill(1));
    }, [state]);

    const handleDragStart = (e: React.DragEvent, side: string, index: number) => {
        e.dataTransfer.setData('molecule', JSON.stringify({ side, index }));
    };

    const handleDrop = (e: React.DragEvent, targetSide: 'reactants' | 'products') => {
        e.preventDefault();
        const data = e.dataTransfer.getData('molecule');
        if (!data) return;
        const { side: sourceSide, index } = JSON.parse(data);

        if (sourceSide === targetSide) return;

        setState(prev => {
            const sourceList = [...(prev as any)[sourceSide]];
            const targetList = [...(prev as any)[targetSide]];
            const [moved] = sourceList.splice(index, 1);
            targetList.push(moved);
            return {
                ...prev,
                [sourceSide]: sourceList,
                [targetSide]: targetList
            };
        });
    };

    return (
        <div className="viz-container">
            <h3 style={{ margin: '0 0 1rem 0', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <FlaskConical size={18} color="var(--accent-color)" />
                {title}
            </h3>

            <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)', marginBottom: '1rem' }}>
                Drag molecules to see the equation balance: 
                <strong style={{ color: 'var(--text-main)', marginLeft: '0.5rem' }}>
                    {state.reactants.map((r, i) => `${coeffs[i] || '?'} ${r}`).join(' + ')} 
                    {' -> '}
                    {state.products.map((p, i) => `${coeffs[state.reactants.length + i] || '?'} ${p}`).join(' + ')}
                </strong>
            </p>

            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', overflowX: 'auto', paddingBottom: '1rem' }}>
                {/* Reactants Drop Zone */}
                <div 
                    onDragOver={(e) => e.preventDefault()}
                    onDrop={(e) => handleDrop(e, 'reactants')}
                    style={{ 
                        flex: 1, 
                        minHeight: '150px', 
                        border: '2px dashed var(--border-color)', 
                        borderRadius: '0.5rem',
                        padding: '1rem',
                        display: 'flex',
                        gap: '0.5rem',
                        flexWrap: 'wrap',
                        background: 'rgba(0,0,0,0.1)'
                    }}
                >
                    {/* Fixed MolCard props mapping */}
                    {state.reactants.map((r, i) => (
                        <MolCard 
                            key={`${r}-${i}-r`} 
                            formula={String(r)} 
                            count={Number(coeffs[i] || 1)} 
                            side="reactants" 
                            index={i} 
                            onDragStart={handleDragStart} 
                        />
                    ))}
                    {state.reactants.length === 0 && <span style={{ margin: 'auto', color: 'var(--text-muted)' }}>Drop Reactants Here</span>}
                </div>

                <ArrowRight size={24} style={{ color: 'var(--text-muted)' }} />

                {/* Products Drop Zone */}
                <div 
                    onDragOver={(e) => e.preventDefault()}
                    onDrop={(e) => handleDrop(e, 'products')}
                    style={{ 
                        flex: 1, 
                        minHeight: '150px', 
                        border: '2px dashed var(--border-color)', 
                        borderRadius: '0.5rem',
                        padding: '1rem',
                        display: 'flex',
                        gap: '0.5rem',
                        flexWrap: 'wrap',
                        background: 'rgba(0,0,0,0.1)'
                    }}
                >
                    {/* Fixed MolCard props mapping */}
                    {state.products.map((p, i) => (
                        <MolCard 
                            key={`${p}-${i}-p`} 
                            formula={String(p)} 
                            count={Number(coeffs[state.reactants.length + i] || 1)} 
                            side="products" 
                            index={i} 
                            onDragStart={handleDragStart} 
                        />
                    ))}
                    {state.products.length === 0 && <span style={{ margin: 'auto', color: 'var(--text-muted)' }}>Drop Products Here</span>}
                </div>
            </div>

            <button onClick={() => setState({ reactants: ["CH4", "O2"], products: ["CO2", "H2O"] })} className="btn" style={{ marginTop: '0.5rem' }}>
                <RefreshCw size={14} /> Reset to Methane Combustion
            </button>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { 
  Download, 
  Upload, 
  FileJson, 
  Settings, 
  X,
  Palette,
  PanelLeft,
  FileText,
  ExternalLink,
  Check
} from 'lucide-react';
import { Sidebar } from './components/Sidebar';
import { Editor } from './components/Editor';
import { FileNode, NodeType, ImportData, AppTheme } from './types';
import { initialNodes } from './initialData';

const themes: Record<string, AppTheme> = {
  dark: {
    name: 'Dark',
    bgMain: '#030712', 
    bgSidebar: '#111827',
    textMain: '#f3f4f6', 
    textMuted: '#9ca3af', 
    border: '#1f2937', 
    accent: '#3b82f6', 
    hover: 'rgba(255, 255, 255, 0.05)'
  },
  light: {
    name: 'Light',
    bgMain: '#ffffff',
    bgSidebar: '#f3f4f6',
    textMain: '#111827',
    textMuted: '#6b7280',
    border: '#e5e7eb',
    accent: '#3b82f6', 
    hover: 'rgba(0, 0, 0, 0.05)'
  },
  navy: {
    name: 'Navy',
    bgMain: '#0a192f',
    bgSidebar: '#112240',
    textMain: '#ccd6f6',
    textMuted: '#8892b0',
    border: '#233554',
    accent: '#64ffda',
    hover: 'rgba(100, 255, 218, 0.1)'
  },
  dracula: {
    name: 'Dracula',
    bgMain: '#282a36',
    bgSidebar: '#21222c',
    textMain: '#f8f8f2',
    textMuted: '#6272a4',
    border: '#44475a',
    accent: '#ff79c6',
    hover: 'rgba(255, 255, 255, 0.1)'
  }
};

export default function App() {
  const [nodes, setNodes] = useState<FileNode[]>(() => {
    const saved = localStorage.getItem('mathsci-fs');
    return saved ? JSON.parse(saved) : initialNodes;
  });
  const [activeFileId, setActiveFileId] = useState<string | null>('file-intro');
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(['folder-welcome', 'folder-docs']));
  const [showSettings, setShowSettings] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  const [currentTheme, setCurrentTheme] = useState<AppTheme>(() => {
    const saved = localStorage.getItem('mathsci-theme');
    return saved ? JSON.parse(saved) : themes.dark;
  });

  useEffect(() => {
    const root = document.documentElement;
    root.style.setProperty('--bg-main', currentTheme.bgMain);
    root.style.setProperty('--bg-sidebar', currentTheme.bgSidebar);
    root.style.setProperty('--bg-toolbar', currentTheme.bgSidebar);
    root.style.setProperty('--text-main', currentTheme.textMain);
    root.style.setProperty('--text-muted', currentTheme.textMuted);
    root.style.setProperty('--border-color', currentTheme.border);
    root.style.setProperty('--accent-color', currentTheme.accent);
    root.style.setProperty('--hover-bg', currentTheme.hover);
    localStorage.setItem('mathsci-theme', JSON.stringify(currentTheme));
  }, [currentTheme]);

  useEffect(() => {
    localStorage.setItem('mathsci-fs', JSON.stringify(nodes));
  }, [nodes]);

  const activeNode = nodes.find(n => n.id === activeFileId);

  const handleCustomColor = (key: keyof AppTheme, color: string) => {
    setCurrentTheme(prev => ({ ...prev, [key]: color }));
  };

  const exportToJson = () => {
    const data: ImportData = { version: 1, nodes };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `mathsci-backup.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importFromJson = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string) as ImportData;
        if (data.nodes) {
          setNodes(data.nodes);
          setActiveFileId(data.nodes.find(n => n.type === NodeType.FILE)?.id || null);
        }
      } catch (err) {
        alert("Invalid workspace file.");
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const exportToPdf = () => {
    const element = document.getElementById('markdown-preview');
    if (!element) return;
    const opt = {
      margin: 10,
      filename: `${activeNode?.name || 'document'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };
    window.html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="app-container">
      <div className="sidebar-wrapper" style={{ width: isSidebarOpen ? '280px' : '0' }}>
         <Sidebar 
            nodes={nodes}
            activeFileId={activeFileId}
            expandedFolders={expandedFolders}
            onFileSelect={setActiveFileId}
            onToggleFolder={(id) => setExpandedFolders(prev => {
                const next = new Set(prev);
                if (next.has(id)) next.delete(id); else next.add(id);
                return next;
            })}
            onAddFile={(parentId) => {
                const id = uuidv4();
                setNodes(prev => [...prev, { id, parentId, name: 'Untitled.md', type: NodeType.FILE, content: '', createdAt: Date.now() }]);
                setActiveFileId(id);
            }}
            onAddFolder={(parentId) => {
                setNodes(prev => [...prev, { id: uuidv4(), parentId, name: 'New Folder', type: NodeType.FOLDER, content: '', createdAt: Date.now() }]);
            }}
            onDeleteNode={(id) => {
                setNodes(prev => prev.filter(n => n.id !== id));
                if (activeFileId === id) setActiveFileId(null);
            }}
            onRenameNode={(id, name) => setNodes(prev => prev.map(n => n.id === id ? { ...n, name } : n))}
            onMoveNode={(id, parentId) => setNodes(prev => prev.map(n => n.id === id ? { ...n, parentId } : n))}
         />
      </div>

      <div className="main-content" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div className="toolbar">
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="btn-icon">
                  <PanelLeft size={18} />
                </button>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <h1 className="app-title">MathSci</h1>
                    <a href="https://orcid.org" target="_blank" rel="noopener noreferrer" className="btn" style={{ padding: '0.1rem 0.4rem', borderColor: '#a6ce39', color: '#a6ce39', fontSize: '10px' }}>
                        ORCID <ExternalLink size={10} style={{ marginLeft: '2px' }} />
                    </a>
                </div>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                <button onClick={() => setShowSettings(true)} className="btn">
                    <Palette size={14} /> Theme
                </button>
                <div className="divider"></div>
                <button onClick={exportToPdf} className="btn"><Download size={14} style={{ color: '#f87171' }}/> PDF</button>
                <label className="btn" style={{ cursor: 'pointer' }}>
                    <Upload size={14} style={{ color: '#4ade80' }}/> Import
                    <input type="file" accept=".json" style={{ display: 'none' }} onChange={importFromJson}/>
                </label>
                <button onClick={exportToJson} className="btn"><FileJson size={14} style={{ color: '#facc15' }}/> Backup</button>
            </div>
        </div>

        <div style={{ flex: 1, overflow: 'hidden' }}>
            {activeNode ? (
                <Editor 
                    content={activeNode.content} 
                    fileName={activeNode.name}
                    onChange={(content) => setNodes(prev => prev.map(n => n.id === activeFileId ? { ...n, content } : n))} 
                />
            ) : (
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-muted)' }}>
                    <p>Select a file from the explorer</p>
                </div>
            )}
        </div>
      </div>

      {showSettings && (
          <div className="modal-overlay">
              <div className="modal" style={{ maxWidth: '400px', background: '#0f172a', color: '#f8fafc', border: '1px solid #1e293b' }}>
                  <div className="modal-header" style={{ borderBottom: '1px solid #1e293b', padding: '1rem' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                        <Palette size={18} color="#3b82f6" />
                        <span style={{ fontSize: '1rem', fontWeight: 600 }}>Theme Settings</span>
                      </div>
                      <button onClick={() => setShowSettings(false)} className="btn-icon"><X size={20}/></button>
                  </div>
                  <div className="modal-body" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                      <div>
                        <label style={{ fontSize: '0.8rem', color: '#94a3b8', marginBottom: '0.75rem', display: 'block' }}>Presets</label>
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.5rem' }}>
                            {Object.entries(themes).map(([k, t]) => (
                                <button 
                                    key={k} 
                                    onClick={() => setCurrentTheme(t)} 
                                    style={{ 
                                        padding: '0.75rem', 
                                        borderRadius: '6px', 
                                        background: t.bgMain, 
                                        color: t.textMain, 
                                        border: `1px solid ${currentTheme.name === t.name ? '#3b82f6' : '#1e293b'}`,
                                        cursor: 'pointer',
                                        display: 'flex',
                                        alignItems: 'center',
                                        gap: '0.5rem',
                                        fontSize: '0.85rem'
                                    }}
                                >
                                    <div style={{ width: 12, height: 12, borderRadius: '50%', background: t.accent }} />
                                    {t.name}
                                </button>
                            ))}
                        </div>
                      </div>

                      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        <label style={{ fontSize: '0.8rem', color: '#94a3b8', display: 'block' }}>Custom Colors</label>
                        {[
                            { label: 'Main Background', key: 'bgMain' },
                            { label: 'Sidebar Background', key: 'bgSidebar' },
                            { label: 'Text Color', key: 'textMain' },
                            { label: 'Accent Color', key: 'accent' }
                        ].map(({ label, key }) => (
                            <div key={key} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                                <span style={{ fontSize: '0.85rem' }}>{label}</span>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                    <span style={{ fontSize: '0.75rem', color: '#64748b', fontFamily: 'monospace' }}>{(currentTheme as any)[key]}</span>
                                    <div style={{ position: 'relative', width: 28, height: 28, borderRadius: '4px', border: '1px solid #334155', background: (currentTheme as any)[key] }}>
                                        <input 
                                            type="color" 
                                            value={(currentTheme as any)[key]} 
                                            onChange={(e) => handleCustomColor(key as any, e.target.value)}
                                            style={{ position: 'absolute', inset: 0, opacity: 0, cursor: 'pointer', width: '100%', height: '100%' }}
                                        />
                                    </div>
                                </div>
                            </div>
                        ))}
                      </div>
                  </div>
                  <div className="modal-footer" style={{ borderTop: '1px solid #1e293b', padding: '1rem' }}>
                    <button onClick={() => setShowSettings(false)} className="btn btn-primary" style={{ width: '80px', height: '32px', borderRadius: '6px' }}>Done</button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

import React, { useRef, useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  Terminal, Upload, FileImage, Globe, Copy, Check, X
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, REACTION_TEMPLATE 
} from './templates';

type TabName = 'Write' | 'Insert' | 'Math/Sci';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');
  const [uploadStatus, setUploadStatus] = useState<{name: string, syntax: string} | null>(null);
  const [copied, setCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (readOnly) return null;

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      const syntax = `![${file.name}](${base64})`;
      insertFormat(`\n${syntax}\n`, '', true);
      setUploadStatus({ name: file.name, syntax });
    };
    reader.readAsDataURL(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const copyToClipboard = () => {
    if (uploadStatus) {
      navigator.clipboard.writeText(uploadStatus.syntax);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
    <button 
      onClick={action} 
      className="btn-icon" 
      title={title} 
      style={{ color: color, padding: '0.4rem', borderRadius: '4px' }}
    >
      <Icon size={16} />
    </button>
  );

  const Group = ({ children, label }: { children: React.ReactNode, label?: string }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2px', padding: '0 8px', borderRight: '1px solid var(--border-color)', position: 'relative' }}>
      {children}
      {label && <span style={{ position: 'absolute', bottom: '-4px', left: 0, right: 0, textAlign: 'center', fontSize: '6px', color: 'var(--text-muted)', textTransform: 'uppercase', opacity: 0.6 }}>{label}</span>}
    </div>
  );

  return (
    <div className="editor-toolbar" style={{ borderBottom: '1px solid var(--border-color)', background: 'var(--bg-toolbar)', position: 'relative' }}>
       <div className="flex px-4 py-2 gap-2" style={{ background: 'var(--bg-main)' }}>
          {['Write', 'Insert', 'Math/Sci'].map((tab) => (
             <button
               key={tab}
               onClick={() => setActiveTab(tab as TabName)}
               style={{
                 padding: '0.2rem 0.75rem',
                 fontSize: '0.7rem',
                 fontWeight: 600,
                 borderRadius: '20px',
                 border: '1px solid var(--border-color)',
                 background: activeTab === tab ? 'var(--text-main)' : 'transparent',
                 color: activeTab === tab ? 'var(--bg-main)' : 'var(--text-main)',
