  if (readOnly) return null;

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      // standard markdown syntax: ![alt](data:image/png;base64,...)
      // Ensure no spaces or extra characters wrap the data URI
      const cleanBase64 = base64.trim();
      const syntax = `![${file.name}](${cleanBase64})`;

      insertFormat(`\n${syntax}\n`, '', true);
      setUploadStatus({ name: file.name, syntax });
    };
    reader.readAsDataURL(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
