interface EditorProps {
  content: string;
  fileName: string;
  onChange: (content: string) => void;
  readOnly?: boolean;
}

export const Editor: React.FC<EditorProps> = ({ content, fileName, onChange, readOnly = false }) => {
  const [view, setView] = useState<'split' | 'editor' | 'preview'>('split');
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const markdownComponents = useMemo(() => ({
    a: ({node, ...props}: any) => <a {...props} target="_blank" rel="noopener noreferrer" />,
    img: ({node, src, alt, ...props}: any) => {
      // Basic sanitization: remove whitespace and potential parser artifacts
      let cleanSrc = (src || "").trim();

      // Handle common markdown parser issues where data URIs might be double-wrapped
      if (cleanSrc.startsWith('(') && cleanSrc.endsWith(')')) {
        cleanSrc = cleanSrc.slice(1, -1);
      }

      return (
        <div style={{ margin: '1.5rem 0', textAlign: 'center', display: 'block' }}>
          <img 
            src={cleanSrc} 
            alt={alt || ''} 
            loading="lazy"
            style={{ 
              maxWidth: '100%', 
              height: 'auto', 
              borderRadius: '8px', 
              border: '1px solid var(--border-color)',
              boxShadow: '0 4px 12px rgba(0,0,0,0.3)',
              display: 'inline-block',
              backgroundColor: '#fff' 
            }} 
            onError={(e: any) => {
              e.target.style.display = 'none';
              const p = document.createElement('p');
              p.innerText = `⚠️ Image Preview Error: ${alt || 'Untitled'}`;
              p.style.fontSize = '0.75rem';
              p.style.color = 'var(--text-muted)';
              p.style.border = '1px dashed var(--border-color)';
              p.style.padding = '10px';
              p.style.borderRadius = '4px';
              e.target.parentNode.appendChild(p);
            }}
          />
          {alt && <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '0.5rem', fontStyle: 'italic' }}>{alt}</p>}
        </div>
      );
    },
    code({node, inline, className, children, ...props}: any) {
        const match = /language-([\w-]+)/.exec(className || '');
        if (!inline) {
          const raw = String(children).replace(/\n$/, '');
          switch (match?.[1]) {
            case 'mermaid': return <MermaidDiagram chart={raw} />;
            case 'smiles': return <SmilesDiagram smiles={raw} />;
            case 'plot': return <InteractivePlot configStr={raw} />;
            case 'physics': return <PhysicsSimulation configStr={raw} />;
            case 'sorting': return <SortingVisualizer configStr={raw} />;
            case 'connectivity': return <NetworkConnectivity configStr={raw} />;
            case 'chemical-reaction': return <ChemicalBalancer configStr={raw} />;
            case 'percolation': return <PercolationVisualizer configStr={raw} />;
            case 'search': return <SearchVisualizer configStr={raw} />;
            case 'memory': return <MemoryVisualizer configStr={raw} />;
            case 'stack': return <StackVisualizer configStr={raw} />;
            case 'queue': return <QueueVisualizer configStr={raw} />;
            case 'iterator': return <IteratorVisualizer configStr={raw} />;
            case 'twostack': return <TwoStackVisualizer configStr={raw} />;
            case 'mergesort': return <MergeSortVisualizer configStr={raw} />;
            case 'convexhull': return <ConvexHullVisualizer configStr={raw} />;
            case 'comparator': return <ComparatorVisualizer configStr={raw} />;
          }
        }
        return <code className={className} {...props}>{children}</code>;
    },
    div: ({node, className, ...props}: any) => className?.includes('math-display') ? <div dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:true, throwOnError:false}) || ''}} {...props}/> : <div className={className} {...props}/>,
    span: ({node, className, ...props}: any) => className?.includes('math-inline') ? <span dangerouslySetInnerHTML={{__html: window.katex?.renderToString(props['data-math'], {displayMode:false, throwOnError:false}) || ''}} {...props}/> : <span className={className} {...props}/>
  }), []);

  const insertFormat = (prefix: string, suffix: string = '', blockMode: boolean = false) => {
    if (!textareaRef.current || readOnly) return;
    const { selectionStart: start, selectionEnd: end, value: text } = textareaRef.current;
    const selected = text.substring(start, end);
    let newText = '', newCursor = 0;

    if (blockMode) {
        const hasNewline = text.substring(0, start).endsWith('\n') || start === 0;
        newText = `${text.substring(0, start)}${hasNewline ? '' : '\n'}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + (hasNewline ? 0 : 1) + selected.length;
    } else {
        newText = `${text.substring(0, start)}${prefix}${selected}${suffix}${text.substring(end)}`;
        newCursor = start + prefix.length + selected.length;
    }
    onChange(newText);
    setTimeout(() => { textareaRef.current?.focus(); textareaRef.current?.setSelectionRange(newCursor, newCursor); }, 0);
  };

  return (
    <div className="flex flex-col h-full bg-[var(--bg-main)] text-[var(--text-main)]">
      <div className="border-b bg-[var(--bg-toolbar)] border-[var(--border-color)]">
        <div className="h-10 flex items-center justify-between px-4 border-b border-[var(--border-color)]">
            <div className="text-sm font-mono text-[var(--accent-color)]">{fileName}</div>
            <div className="flex rounded p-0.5 bg-[var(--bg-main)]">
                {['editor', 'split', 'preview'].map((v: any) => (
                    <button key={v} onClick={() => setView(v)} className={`p-1.5 rounded transition-colors ${view===v ? 'bg-[var(--accent-color)] text-white' : 'text-[var(--text-muted)]'}`}>
                        {v==='editor' ? <Edit3 size={14}/> : v==='split' ? <Columns size={14}/> : <Eye size={14}/>}
                    </button>
                ))}
            </div>
        </div>
        {(view !== 'preview' && !readOnly) && <EditorToolbar insertFormat={insertFormat} readOnly={readOnly} />}
      </div>
      <div className="flex-1 flex overflow-hidden">
        {(view === 'split' || view === 'editor') && (
            <div className={`h-full flex flex-col ${view === 'split' ? 'w-1/2 border-r' : 'w-full'} border-[var(--border-color)]`}>
                <textarea 
                  ref={textareaRef} 
                  className="w-full h-full p-4 resize-none focus:outline-none font-mono text-sm leading-relaxed bg-[var(--bg-main)] text-[var(--text-main)]" 
                  value={content} 
                  onChange={e => onChange(e.target.value)} 
                  placeholder="# Start typing..." 
                  spellCheck={false} 
                />
            </div>
        )}
        {(view === 'split' || view === 'preview') && (
            <div id="markdown-preview" className={`h-full overflow-y-auto p-8 ${view === 'split' ? 'w-1/2' : 'w-full'} bg-[var(--bg-main)]`}>
                <div className="markdown-body max-w-4xl mx-auto">
                    <ReactMarkdown 
                        remarkPlugins={[remarkGfm, remarkMath]} 
                        rehypePlugins={[rehypeRaw, rehypeHighlight]}
                        components={markdownComponents as any}
                    >{content}</ReactMarkdown>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef, useState } from 'react';
import { 
  Bold, Italic, Strikethrough, 
  Heading1, Heading2, Heading3, 
  List, ListOrdered, CheckSquare, 
  Quote, Code, Link, Image, Table, Minus,
  Sigma, Workflow, Hexagon, Activity, Atom, 
  Terminal, Upload, FileImage, Globe, Copy, Check, X
} from 'lucide-react';
import { 
  PLOT_TEMPLATE, PHYSICS_TEMPLATE, REACTION_TEMPLATE 
} from './templates';

type TabName = 'Write' | 'Insert' | 'Math/Sci';

export const EditorToolbar = ({ insertFormat, readOnly }: { insertFormat: (p: string, s?: string, b?: boolean) => void, readOnly?: boolean }) => {
  const [activeTab, setActiveTab] = useState<TabName>('Write');
  const [uploadStatus, setUploadStatus] = useState<{name: string, syntax: string} | null>(null);
  const [copied, setCopied] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  if (readOnly) return null;

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result as string;
      const cleanBase64 = base64.trim();

      // Use standard HTML img tag for the inserted content as requested
      // This is often more reliable for very large base64 strings in some parsers
      const syntax = `<img src="${cleanBase64}" alt="${file.name}" />`;

      insertFormat(`\n${syntax}\n`, '', true);
      setUploadStatus({ name: file.name, syntax });
    };
    reader.readAsDataURL(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const copyToClipboard = () => {
    if (uploadStatus) {
      navigator.clipboard.writeText(uploadStatus.syntax);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const ToolbarButton = ({ icon: Icon, title, action, color }: { icon: any, title: string, action: () => void, color?: string }) => (
    <button 
      onClick={action} 
      className="btn-icon" 
      title={title} 
      style={{ color: color, padding: '0.4rem', borderRadius: '4px' }}
    >
      <Icon size={16} />
    </button>
  );

  const Group = ({ children, label }: { children: React.ReactNode, label?: string }) => (
    <div style={{ display: 'flex', alignItems: 'center', gap: '2px', padding: '0 8px', borderRight: '1px solid var(--border-color)', position: 'relative' }}>
      {children}
      {label && <span style={{ position: 'absolute', bottom: '-4px', left: 0, right: 0, textAlign: 'center', fontSize: '6px', color: 'var(--text-muted)', textTransform: 'uppercase', opacity: 0.6 }}>{label}</span>}
    </div>
  );

  return (
    <div className="editor-toolbar" style={{ borderBottom: '1px solid var(--border-color)', background: 'var(--bg-toolbar)', position: 'relative' }}>
       <div className="flex px-4 py-2 gap-2" style={{ background: 'var(--bg-main)' }}>
          {['Write', 'Insert', 'Math/Sci'].map((tab) => (
             <button
               key={tab}
               onClick={() => setActiveTab(tab as TabName)}
               style={{
                 padding: '0.2rem 0.75rem',
                 fontSize: '0.7rem',
                 fontWeight: 600,
                 borderRadius: '20px',
                 border: '1px solid var(--border-color)',
                 background: activeTab === tab ? 'var(--text-main)' : 'transparent',
                 color: activeTab === tab ? 'var(--bg-main)' : 'var(--text-main)',
                 cursor: 'pointer'
               }}
             >
               {tab}
             </button>
          ))}
       </div>

       <div className="px-2 pb-2 flex items-center overflow-x-auto h-12 no-scrollbar">
          {activeTab === 'Write' && (
            <>
              <Group label="Text">
                <ToolbarButton icon={Bold} title="Bold" action={() => insertFormat('**', '**')} />
                <ToolbarButton icon={Italic} title="Italic" action={() => insertFormat('*', '*')} />
                <ToolbarButton icon={Strikethrough} title="Strike" action={() => insertFormat('~~', '~~')} />
              </Group>
              <Group label="Header">
                <ToolbarButton icon={Heading1} title="H1" action={() => insertFormat('# ', '', true)} />
                <ToolbarButton icon={Heading2} title="H2" action={() => insertFormat('## ', '', true)} />
              </Group>
              <Group label="List">
                <ToolbarButton icon={List} title="Unordered" action={() => insertFormat('- ', '', true)} />
                <ToolbarButton icon={CheckSquare} title="Tasks" action={() => insertFormat('- [ ] ', '', true)} />
              </Group>
              <Group label="Misc">
                <ToolbarButton icon={Quote} title="Quote" action={() => insertFormat('> ', '', true)} />
                <ToolbarButton icon={Minus} title="Line" action={() => insertFormat('---\n', '', true)} />
              </Group>
            </>
          )}

          {activeTab === 'Insert' && (
            <>
              <Group label="Media">
                <ToolbarButton icon={Link} title="Web Link" action={() => insertFormat('[text](', ')') } />
                <ToolbarButton icon={Globe} title="Image URL" action={() => insertFormat('![alt](', ')') } />
                <ToolbarButton icon={Upload} title="Upload File" action={() => fileInputRef.current?.click()} color="var(--accent-color)" />
                <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" style={{ display: 'none' }} />
              </Group>
              <Group label="Code">
                <ToolbarButton icon={Code} title="Inline" action={() => insertFormat('`', '`')} />
                <ToolbarButton icon={Terminal} title="Block" action={() => insertFormat('```\n', '\n```', true)} />
              </Group>
              <Group label="Diagram">
                <ToolbarButton icon={Workflow} title="Mermaid" action={() => insertFormat('```mermaid\n', '\n```', true)} color="#c084fc" />
                <ToolbarButton icon={Activity} title="Plotly" action={() => insertFormat(PLOT_TEMPLATE, '', true)} color="#c084fc" />
              </Group>
            </>
          )}

          {activeTab === 'Math/Sci' && (
            <>
              <Group label="LaTeX">
                <ToolbarButton icon={Sigma} title="Math" action={() => insertFormat('$$\n', '\n$$', true)} color="#60a5fa" />
              </Group>
              <Group label="Chemistry">
                <ToolbarButton icon={Hexagon} title="SMILES" action={() => insertFormat('```smiles\n', '\n```', true)} color="#60a5fa" />
                <ToolbarButton icon={Activity} title="Reaction" action={() => insertFormat(REACTION_TEMPLATE, '', true)} color="#60a5fa" />
              </Group>
              <Group label="Physics">
                <ToolbarButton icon={Atom} title="Physics" action={() => insertFormat(PHYSICS_TEMPLATE, '', true)} color="#f87171" />
              </Group>
            </>
          )}
       </div>

       {uploadStatus && (
         <div style={{ 
            position: 'absolute', 
            top: '100%', 
            left: 0, 
            right: 0, 
            zIndex: 100, 
            background: 'var(--bg-sidebar)', 
            borderBottom: '1px solid var(--border-color)',
            padding: '0.5rem 1rem',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            fontSize: '0.75rem',
            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
         }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flex: 1, overflow: 'hidden' }}>
                <FileImage size={14} color="var(--accent-color)" />
                <span style={{ color: 'var(--text-muted)' }}>Uploaded:</span>
                <code style={{ background: 'var(--hover-bg)', padding: '2px 4px', borderRadius: '4px', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                    {uploadStatus.syntax}
                </code>
            </div>
            <div style={{ display: 'flex', gap: '0.5rem', marginLeft: '1rem' }}>
                <button onClick={copyToClipboard} className="btn" style={{ padding: '0.2rem 0.5rem' }}>
                    {copied ? <Check size={12} color="#4ade80" /> : <Copy size={12} />}
                    {copied ? 'Copied' : 'Copy'}
                </button>
                <button onClick={() => setUploadStatus(null)} className="btn-icon" style={{ padding: '2px' }}><X size={14}/></button>
            </div>
         </div>
       )}
    </div>
  );
};

