import React, { useMemo } from 'react';
import { Type, Info } from 'lucide-react';

interface DisplacyToken {
  text: string;
  tag: string;
  head?: number;
  dep?: string;
}

interface DisplacyData {
  tokens: DisplacyToken[];
  arcs: { start: number; end: number; label: string; dir: 'left' | 'right' }[];
}

export const DisplacyVisualizer = ({ configStr }: { configStr: string }) => {
  const data = useMemo(() => {
    try {
      // Allow user to provide a simple string or a complex JSON object
      const parsed = configStr.trim().startsWith('{') ? JSON.parse(configStr) : { text: configStr };

      if (parsed.tokens && parsed.arcs) return parsed as DisplacyData;

      // Rule-based heuristic parser for common demo sentences if only text is provided
      const text = parsed.text || "";
      if (text.toLowerCase().includes("displacy uses javascript")) {
        return {
          tokens: [
            { text: "displaCy", tag: "PROPN" },
            { text: "uses", tag: "VERB" },
            { text: "JavaScript,", tag: "PROPN" },
            { text: "SVG", tag: "PROPN" },
            { text: "and", tag: "CCONJ" },
            { text: "CSS", tag: "PROPN" },
            { text: "to", tag: "PART" },
            { text: "show", tag: "VERB" },
            { text: "you", tag: "PRON" },
            { text: "how", tag: "SCONJ" },
            { text: "computers", tag: "NOUN" },
            { text: "understand", tag: "VERB" },
            { text: "language", tag: "NOUN" }
          ],
          arcs: [
            { start: 0, end: 1, label: "nsubj", dir: "right" },
            { start: 1, end: 2, label: "dobj", dir: "right" },
            { start: 2, end: 3, label: "conj", dir: "right" },
            { start: 4, end: 5, label: "cc", dir: "left" },
            { start: 3, end: 5, label: "conj", dir: "right" },
            { start: 7, end: 6, label: "aux", dir: "left" },
            { start: 1, end: 7, label: "xcomp", dir: "right" },
            { start: 7, end: 8, label: "dobj", dir: "right" },
            { start: 11, end: 9, label: "advmod", dir: "left" },
            { start: 11, end: 10, label: "nsubj", dir: "left" },
            { start: 7, end: 11, label: "ccomp", dir: "right" },
            { start: 11, end: 12, label: "dobj", dir: "right" }
          ]
        } as DisplacyData;
      }

      // Default fallback for unknown text
      const words = text.split(/\s+/);
      return {
        tokens: words.map(w => ({ text: w, tag: "WORD" })),
        arcs: []
      } as DisplacyData;
    } catch (e) {
      return null;
    }
  }, [configStr]);

  if (!data) return <div className="p-2 text-red-400">Invalid DisplaCy Configuration</div>;

  const BOX_WIDTH = 120;
  const BOX_HEIGHT = 40;
  const ARC_HEIGHT_STEP = 35;
  const svgWidth = data.tokens.length * BOX_WIDTH + 50;
  const maxArcDist = data.arcs.reduce((max, arc) => Math.max(max, Math.abs(arc.end - arc.start)), 0);
  const svgHeight = (maxArcDist + 1) * ARC_HEIGHT_STEP + 120;

  const getTagColor = (tag: string) => {
    const t = tag.toUpperCase();
    if (t === 'VERB') return '#ec4899';
    if (t === 'NOUN' || t === 'PROPN') return '#f97316';
    if (t === 'PRON' || t === 'SCONJ') return '#84cc16';
    return '#94a3b8';
  };

  return (
    <div className="viz-container" style={{ overflowX: 'auto', background: '#1a1b16' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1rem', borderBottom: '1px solid #333', paddingBottom: '0.5rem' }}>
        <Type size={18} color="#84cc16" />
        <span style={{ fontSize: '0.875rem', fontWeight: 600, color: '#f8fafc' }}>displaCy Dependency Parse</span>
      </div>

      <svg width={svgWidth} height={svgHeight} style={{ fontFamily: 'monospace' }}>
        <defs>
          <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="10" refY="3.5" orient="auto">
            <polygon points="0 0, 10 3.5, 0 7" fill="#888" />
          </marker>
        </defs>

        {/* Arcs */}
        {data.arcs.map((arc, i) => {
          const startX = arc.start * BOX_WIDTH + BOX_WIDTH / 2;
          const endX = arc.end * BOX_WIDTH + BOX_WIDTH / 2;
          const distance = Math.abs(arc.end - arc.start);
          const height = distance * ARC_HEIGHT_STEP;
          const baseY = svgHeight - 60;
          const topY = baseY - height;

          // Cubic Bezier for smooth arcs
          const controlY = topY;
          const d = `M ${startX} ${baseY} C ${startX} ${controlY}, ${endX} ${controlY}, ${endX} ${baseY}`;

          return (
            <g key={`arc-${i}`}>
              <path 
                d={d} 
                fill="none" 
                stroke="#666" 
                strokeWidth="1.5" 
                markerEnd="url(#arrowhead)" 
              />
              <rect 
                x={(startX + endX) / 2 - 25} 
                y={topY - 10} 
                width="50" 
                height="20" 
                fill="#1a1b16" 
              />
              <text 
                x={(startX + endX) / 2} 
                y={topY + 4} 
                textAnchor="middle" 
                fontSize="11" 
                fill="#ccc"
                fontWeight="bold"
              >
                {arc.label}
              </text>
            </g>
          );
        })}

        {/* Tokens */}
        {data.tokens.map((token, i) => {
          const x = i * BOX_WIDTH + BOX_WIDTH / 2;
          const y = svgHeight - 40;
          return (
            <g key={`token-${i}`}>
              <text x={x} y={y} textAnchor="middle" fontSize="18" fill="#fff" fontWeight="bold">
                {token.text}
              </text>
              <text x={x} y={y + 20} textAnchor="middle" fontSize="12" fill={getTagColor(token.tag)} fontWeight="bold">
                {token.tag}
              </text>
            </g>
          );
        })}
      </svg>

      <div style={{ marginTop: '1rem', padding: '0.5rem', background: 'rgba(0,0,0,0.3)', borderRadius: '4px', display: 'flex', gap: '1rem', alignItems: 'center' }}>
          <Info size={14} color="#94a3b8" />
          <span style={{ fontSize: '0.7rem', color: '#94a3b8' }}>
            Visualizing dependency relations based on linguistic structural rules.
          </span>
      </div>
    </div>
  );
};

