    img: ({node, src, alt, ...props}: any) => {
      let cleanSrc = (src || "").trim();

      // Remove artifacts like extra parentheses or quotes that might be left by the parser
      if (cleanSrc.startsWith('(') && cleanSrc.endsWith(')')) cleanSrc = cleanSrc.slice(1, -1);
      if (cleanSrc.startsWith("'") && cleanSrc.endsWith("'")) cleanSrc = cleanSrc.slice(1, -1);
      if (cleanSrc.startsWith('"') && cleanSrc.endsWith('"')) cleanSrc = cleanSrc.slice(1, -1);

      return (
        <div style={{ margin: '1.5rem 0', textAlign: 'center', display: 'block' }}>
          <img 
            src={cleanSrc} 
            alt={alt || ''} 
            loading="lazy"
            style={{ 
              maxWidth: '100%', 
              height: 'auto', 
              borderRadius: '8px', 
              border: '1px solid var(--border-color)',
              boxShadow: '0 4px 12px rgba(0,0,0,0.3)',
              display: 'inline-block',
              backgroundColor: '#fff' 
