        { start: 11, end: 9, label: "advmod", dir: "left" },
        { start: 11, end: 10, label: "nsubj", dir: "left" },
        { start: 7, end: 11, label: "ccomp", dir: "right" },
        { start: 11, end: 12, label: "dobj", dir: "right" }
      ]
    };
  }
  // Generic fallback
  return {
    words: text.split(/\s+/).map(t => ({ text: t, tag: "WORD" })),
    arcs: []
  };
};

export const DisplacyVisualizer = ({ configStr }: { configStr: string }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let isMounted = true;

    const initDisplacy = async () => {
      // Import the library from the window/import map
      // The library v1.1.0 usually exports a global 'displacy' or can be imported
      const displacyModule = (window as any).displacy;

      if (!displacyModule || !containerRef.current) return;

      try {
        const instance = new displacyModule('', {
          container: containerRef.current,
          format: 'spacy', // Use standard spacy format
          distance: 200,
          offsetX: 50,
          arrowSpacing: 10,
          arrowWidth: 8,
          arrowHeight: 4,
          wordSpacing: 40,
          font: 'inherit',
          color: '#ffffff',
          bg: '#1a1b16'
        });

        // Parse config
        let data;
        const trimmed = configStr.trim();
        if (trimmed.startsWith('{')) {
          const parsed = JSON.parse(trimmed);
          // Standard displacy format uses 'words' and 'arcs'
          data = {
            words: parsed.words || parsed.tokens || [],
            arcs: parsed.arcs || []
          };
        } else {
          data = GET_DEMO_DATA(trimmed);
        }

        if (isMounted) {
          containerRef.current.innerHTML = ''; // Clear previous
          instance.render(data);

          // Apply some custom styling to the generated SVG for better dark mode compatibility
          const svg = containerRef.current.querySelector('svg');
          if (svg) {
            svg.style.maxWidth = 'none';
            svg.style.height = 'auto';
            svg.style.overflow = 'visible';
          }
        }
      } catch (err) {
        console.error("Displacy rendering error:", err);
      }
    };

    initDisplacy();
    return () => { isMounted = false; };
  }, [configStr]);

  return (
    <div className="viz-container" style={{ background: '#1a1b16', minHeight: '150px' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1rem', borderBottom: '1px solid #333', paddingBottom: '0.5rem' }}>
        <Type size={18} color="#84cc16" />
        <span style={{ fontSize: '0.875rem', fontWeight: 600, color: '#f8fafc' }}>displaCy v1.1.0 Parser</span>
      </div>

      <div 
        ref={containerRef} 
        className="displacy"
        style={{ 
          width: '100%', 
          overflowX: 'auto',
          padding: '20px 0'
        }} 
      />

      <div style={{ marginTop: '1rem', padding: '0.5rem', background: 'rgba(0,0,0,0.3)', borderRadius: '4px', display: 'flex', gap: '1rem', alignItems: 'center' }}>
          <Info size={14} color="#94a3b8" />
          <span style={{ fontSize: '0.7rem', color: '#94a3b8' }}>
            Powered by explosion/displaCy. Visualizing dependency relations.
          </span>
      </div>
    </div>
  );
};

