// Enhanced heuristic parser for any text input
const parseToDisplacyFormat = (text: string) => {
  const trimmed = text.trim();

  // If user provided raw JSON, use it
  if (trimmed.startsWith('{')) {
    try {
      const parsed = JSON.parse(trimmed);
      return {
        words: parsed.words || parsed.tokens || [],
        arcs: parsed.arcs || []
      };
    } catch (e) {
      console.error("JSON parse error in DisplaCy", e);
    }
  }

  // Otherwise, heuristic tokenization for plain text
  const tokens = trimmed.split(/\s+/).filter(t => t.length > 0);

  // Check if it's our specific demo sentence for full metadata
  if (trimmed.toLowerCase().includes("displacy uses javascript")) {
    return {
      words: [
        { text: "displaCy", tag: "PROPN" }, { text: "uses", tag: "VERB" },
        { text: "JavaScript,", tag: "PROPN" }, { text: "SVG", tag: "PROPN" },
        { text: "and", tag: "CCONJ" }, { text: "CSS", tag: "PROPN" },
        { text: "to", tag: "PART" }, { text: "show", tag: "VERB" },
        { text: "you", tag: "PRON" }, { text: "how", tag: "SCONJ" },
        { text: "computers", tag: "NOUN" }, { text: "understand", tag: "VERB" },
        { text: "language", tag: "NOUN" }
      ],
      arcs: [
        { start: 0, end: 1, label: "nsubj", dir: "right" },
        { start: 1, end: 2, label: "dobj", dir: "right" },
        { start: 2, end: 3, label: "conj", dir: "right" },
        { start: 4, end: 5, label: "cc", dir: "left" },
        { start: 3, end: 5, label: "conj", dir: "right" },
        { start: 7, end: 6, label: "aux", dir: "left" },
        { start: 1, end: 7, label: "xcomp", dir: "right" },
        { start: 7, end: 8, label: "dobj", dir: "right" },
        { start: 11, end: 9, label: "advmod", dir: "left" },
        { start: 11, end: 10, label: "nsubj", dir: "left" },
        { start: 7, end: 11, label: "ccomp", dir: "right" },
        { start: 11, end: 12, label: "dobj", dir: "right" }
      ]
    };
  }

  // Basic representation for any other text
  return {
    words: tokens.map((t, i) => ({ 
      text: t, 
      tag: t.length > 5 ? "NOUN" : (t.length < 3 ? "DET" : "VERB") // Dumb heuristic POS tags
    })),
    arcs: tokens.slice(0, -1).map((_, i) => ({
      start: i,
      end: i + 1,
      label: "dep",
      dir: "right"
    }))
  };
};

